hooks.command:
python3 -c "
import sys, json, subprocess, os
try:
    d = json.load(sys.stdin)
    f = d.get('file_path', '')
    if f.endswith('.kt') and 'src/main' in f:
        backend_dir = f[:f.index('/backend/') + len('/backend/')]
        r = subprocess.run(['./gradlew', 'compileKotlin', '--quiet'], cwd=backend_dir, capture_output=True, text=True, timeout=120)
        if r.returncode != 0:
            print('COMPILE ERROR (fix before continuing):', file=sys.stderr)
            print(r.stdout or r.stderr, file=sys.stderr)
            sys.exit(1)
    elif f.endswith(('.ts', '.tsx')):
        subprocess.run(['npx', 'prettier', '--write', f], capture_output=True)
except json.JSONDecodeError as e:
    print(f'Hook input error: {e}', file=sys.stderr)
except subprocess.TimeoutExpired:
    print('compileKotlin timed out (120s)', file=sys.stderr)
except ValueError:
    pass  # file_path does not contain /backend/ — not a backend file
except Exception as e:
    print(f'Hook error: {e}', file=sys.stderr)
"
